-- ============================================================================
-- Quiz Seed: 1 Peter (Chapters 1–5)
-- 3 difficulties × 5 chapters = 80 total questions
--   kids:   3 per chapter  = 15
--   teens:  5 per chapter  = 25
--   adults: 8 per chapter  = 40
-- ============================================================================

-- ═══ 1 Peter Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Peter', 1, 'kids', 1, 'Who wrote this letter?', 'Peter, an apostle of Jesus Christ', 'Paul', 'James', 'John', 'a', '1 Peter 1:1 — "Peter, an apostle of Jesus Christ, to the strangers scattered throughout Pontus, Galatia, Cappadocia, Asia, and Bithynia."'),
('1 Peter', 1, 'kids', 2, 'What kind of hope do believers have through Jesus?', 'A living hope because Jesus rose from the dead', 'A fading hope that might not come true', 'A hope only for this life', 'A hope based on being good enough', 'a', '1 Peter 1:3 — "Hath begotten us again unto a lively hope by the resurrection of Jesus Christ from the dead."'),
('1 Peter', 1, 'kids', 3, 'What does Peter say is more precious than gold?', 'The trial of your faith', 'A bag of diamonds', 'A king''s crown', 'A beautiful palace', 'a', '1 Peter 1:7 — "That the trial of your faith, being much more precious than of gold that perisheth, though it be tried with fire."'),
-- Teens
('1 Peter', 1, 'teens', 1, 'How does Peter describe the believers'' inheritance?', 'Incorruptible, undefiled, and that fadeth not away, reserved in heaven', 'Earthly land promised to Abraham''s children', 'Gold and silver stored in the temple', 'Political freedom from Roman rule', 'a', '1 Peter 1:4 — "To an inheritance incorruptible, and undefiled, and that fadeth not away, reserved in heaven for you."'),
('1 Peter', 1, 'teens', 2, 'Why are trials of faith valuable?', 'That the trial of your faith might be found unto praise and honour and glory at the appearing of Jesus Christ', 'So believers can boast about their suffering', 'So God can separate the weak from the strong', 'So the world will pity Christians', 'a', '1 Peter 1:7 — "That the trial of your faith, being much more precious than of gold that perisheth, though it be tried with fire, might be found unto praise and honour and glory at the appearing of Jesus Christ."'),
('1 Peter', 1, 'teens', 3, 'What does Peter say believers should be?', 'Holy, for God is holy', 'Wealthy, for God owns everything', 'Popular, for God loves all people', 'Powerful, for God is almighty', 'a', '1 Peter 1:15-16 — "But as he which hath called you is holy, so be ye holy in all manner of conversation; Because it is written, Be ye holy; for I am holy."'),
('1 Peter', 1, 'teens', 4, 'What were believers redeemed with?', 'The precious blood of Christ, as of a lamb without blemish and without spot', 'Silver and gold from the temple treasury', 'Good works and righteous deeds', 'The prayers of the saints', 'a', '1 Peter 1:18-19 — "Ye were not redeemed with corruptible things, as silver and gold... But with the precious blood of Christ, as of a lamb without blemish and without spot."'),
('1 Peter', 1, 'teens', 5, 'How long does the word of the Lord endure?', 'For ever', 'For a thousand years', 'Until the end of this age', 'Only during our lifetime', 'a', '1 Peter 1:25 — "But the word of the Lord endureth for ever. And this is the word which by the gospel is preached unto you."'),
-- Adults
('1 Peter', 1, 'adults', 1, 'To whom does Peter address this letter?', 'Strangers scattered throughout Pontus, Galatia, Cappadocia, Asia, and Bithynia', 'The church at Rome', 'The twelve tribes of Israel', 'The Gentile churches founded by Paul', 'a', '1 Peter 1:1 — "Peter, an apostle of Jesus Christ, to the strangers scattered throughout Pontus, Galatia, Cappadocia, Asia, and Bithynia."'),
('1 Peter', 1, 'adults', 2, 'What three aspects of the Trinity are mentioned in verse 2?', 'Foreknowledge of God the Father, sanctification of the Spirit, sprinkling of the blood of Jesus Christ', 'Creation by the Father, incarnation of the Son, indwelling of the Spirit', 'Wrath of the Father, sacrifice of the Son, comfort of the Spirit', 'Sovereignty of the Father, teaching of the Son, gifts of the Spirit', 'a', '1 Peter 1:2 — "Elect according to the foreknowledge of God the Father, through sanctification of the Spirit, unto obedience and sprinkling of the blood of Jesus Christ."'),
('1 Peter', 1, 'adults', 3, 'What did the Old Testament prophets search and inquire about?', 'What, or what manner of time the Spirit of Christ which was in them did signify', 'When the Messiah would overthrow Rome', 'How to build the second temple', 'Where the lost tribes of Israel had gone', 'a', '1 Peter 1:10-11 — "Of which salvation the prophets have enquired and searched diligently... Searching what, or what manner of time the Spirit of Christ which was in them did signify."'),
('1 Peter', 1, 'adults', 4, 'What does Peter say even the angels desire?', 'To look into the things of the gospel', 'To become human and experience salvation', 'To worship in the earthly temple', 'To rule over earthly kingdoms', 'a', '1 Peter 1:12 — "Which things the angels desire to look into."'),
('1 Peter', 1, 'adults', 5, 'What does Peter tell believers to gird up?', 'The loins of your mind', 'Your physical strength', 'Your financial resources', 'Your political alliances', 'a', '1 Peter 1:13 — "Wherefore gird up the loins of your mind, be sober, and hope to the end for the grace that is to be brought unto you at the revelation of Jesus Christ."'),
('1 Peter', 1, 'adults', 6, 'How were believers born again according to verse 23?', 'Not of corruptible seed, but of incorruptible, by the word of God which liveth and abideth for ever', 'By water baptism in the Jordan River', 'Through the laying on of apostolic hands', 'By circumcision and keeping the law', 'a', '1 Peter 1:23 — "Being born again, not of corruptible seed, but of incorruptible, by the word of God, which liveth and abideth for ever."'),
('1 Peter', 1, 'adults', 7, 'What does Peter compare human life to in verse 24?', 'All flesh is as grass, and all the glory of man as the flower of grass that withereth', 'A mighty cedar tree that stands for centuries', 'A rock that endures through all storms', 'A river that flows without ceasing', 'a', '1 Peter 1:24 — "For all flesh is as grass, and all the glory of man as the flower of grass. The grass withereth, and the flower thereof falleth away."'),
('1 Peter', 1, 'adults', 8, 'What does Peter say about believers'' relationship with Christ whom they have not seen?', 'Whom having not seen, ye love; in whom ye rejoice with joy unspeakable and full of glory', 'Whom not seeing, ye doubt and question', 'Whom having not seen, ye fear and tremble', 'Whom not seeing, ye wait with uncertainty', 'a', '1 Peter 1:8 — "Whom having not seen, ye love; in whom, though now ye see him not, yet believing, ye rejoice with joy unspeakable and full of glory."');

-- ═══ 1 Peter Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Peter', 2, 'kids', 1, 'What does Peter call believers?', 'A chosen generation and a royal priesthood', 'A group of ordinary people', 'A gathering of sinners', 'A collection of strangers', 'a', '1 Peter 2:9 — "But ye are a chosen generation, a royal priesthood, an holy nation, a peculiar people."'),
('1 Peter', 2, 'kids', 2, 'Who is the chief corner stone that Peter talks about?', 'Jesus Christ', 'Abraham', 'Moses', 'King David', 'a', '1 Peter 2:6 — "Behold, I lay in Sion a chief corner stone, elect, precious: and he that believeth on him shall not be confounded."'),
('1 Peter', 2, 'kids', 3, 'What did Jesus do when people said mean things to him?', 'He did not answer back with mean words', 'He yelled at them loudly', 'He ran away from them', 'He called down fire from heaven', 'a', '1 Peter 2:23 — "Who, when he was reviled, reviled not again; when he suffered, he threatened not."'),
-- Teens
('1 Peter', 2, 'teens', 1, 'What should believers desire like newborn babies?', 'The sincere milk of the word, that they may grow thereby', 'Wealth and earthly possessions', 'Power and influence in society', 'The praise and approval of men', 'a', '1 Peter 2:2 — "As newborn babes, desire the sincere milk of the word, that ye may grow thereby."'),
('1 Peter', 2, 'teens', 2, 'What are believers called to be built up as?', 'A spiritual house and a holy priesthood to offer up spiritual sacrifices', 'A physical temple made of stone', 'An earthly kingdom with a human king', 'A military army for God', 'a', '1 Peter 2:5 — "Ye also, as lively stones, are built up a spiritual house, an holy priesthood, to offer up spiritual sacrifices, acceptable to God by Jesus Christ."'),
('1 Peter', 2, 'teens', 3, 'What does Peter say about submitting to human authorities?', 'Submit to every ordinance of man for the Lord''s sake', 'Rebel against all earthly rulers', 'Only obey rulers who are Christians', 'Ignore all government completely', 'a', '1 Peter 2:13 — "Submit yourselves to every ordinance of man for the Lord''s sake: whether it be to the king, as supreme."'),
('1 Peter', 2, 'teens', 4, 'What happened to the stone the builders disallowed (rejected)?', 'It became the head of the corner', 'It was thrown away forever', 'It was ground into dust', 'It was used for a lesser purpose', 'a', '1 Peter 2:7 — "The stone which the builders disallowed, the same is made the head of the corner."'),
('1 Peter', 2, 'teens', 5, 'By whose stripes are believers healed?', 'By the stripes of Christ', 'By the stripes of the prophets', 'By the stripes of the apostles', 'By the stripes of Moses', 'a', '1 Peter 2:24 — "By whose stripes ye were healed."'),
-- Adults
('1 Peter', 2, 'adults', 1, 'What does Peter call Christ in verse 4?', 'A living stone, disallowed indeed of men, but chosen of God, and precious', 'The great high priest after the order of Melchisedec', 'The Lion of the tribe of Judah', 'The bright and morning star', 'a', '1 Peter 2:4 — "To whom coming, as unto a living stone, disallowed indeed of men, but chosen of God, and precious."'),
('1 Peter', 2, 'adults', 2, 'What does Christ become to those who are disobedient?', 'A stone of stumbling, and a rock of offence', 'A light shining in the darkness', 'A refuge in the time of storm', 'A healer of their wounds', 'a', '1 Peter 2:8 — "And a stone of stumbling, and a rock of offence, even to them which stumble at the word, being disobedient."'),
('1 Peter', 2, 'adults', 3, 'What four titles does Peter give believers in verse 9?', 'A chosen generation, a royal priesthood, an holy nation, a peculiar people', 'Apostles, prophets, evangelists, and pastors', 'Children, servants, soldiers, and ambassadors', 'Priests, Levites, scribes, and Pharisees', 'a', '1 Peter 2:9 — "But ye are a chosen generation, a royal priesthood, an holy nation, a peculiar people; that ye should shew forth the praises of him who hath called you out of darkness into his marvellous light."'),
('1 Peter', 2, 'adults', 4, 'What does Peter say servants should do regarding their masters?', 'Be subject to masters with all fear, not only to the good and gentle but also to the froward', 'Only obey kind and fair masters', 'Refuse to serve unkind masters', 'Flee from harsh masters', 'a', '1 Peter 2:18 — "Servants, be subject to your masters with all fear; not only to the good and gentle, but also to the froward."'),
('1 Peter', 2, 'adults', 5, 'What is thankworthy (acceptable) in God''s sight?', 'If a man for conscience toward God endure grief, suffering wrongfully', 'If a man accumulates great wealth for the church', 'If a man gains political power to spread the gospel', 'If a man avoids all suffering through wisdom', 'a', '1 Peter 2:19 — "For this is thankworthy, if a man for conscience toward God endure grief, suffering wrongfully."'),
('1 Peter', 2, 'adults', 6, 'What does Christ''s example teach about suffering?', 'When he suffered, he threatened not, but committed himself to him that judgeth righteously', 'When he suffered, he called for legions of angels', 'When he suffered, he promised vengeance on his enemies', 'When he suffered, he cursed those who persecuted him', 'a', '1 Peter 2:23 — "Who, when he was reviled, reviled not again; when he suffered, he threatened not; but committed himself to him that judgeth righteously."'),
('1 Peter', 2, 'adults', 7, 'What did Christ bear in his own body on the tree?', 'Our sins, that we being dead to sins should live unto righteousness', 'The curse of the law only', 'The punishment for Adam''s sin alone', 'The weight of the entire world', 'a', '1 Peter 2:24 — "Who his own self bare our sins in his own body on the tree, that we, being dead to sins, should live unto righteousness."'),
('1 Peter', 2, 'adults', 8, 'What were believers before, but now have returned to whom?', 'As sheep going astray, but are now returned unto the Shepherd and Bishop of your souls', 'As wolves in sheep''s clothing, but now are true believers', 'As wandering stars, but now are fixed in heaven', 'As lost coins, but now are found by the angels', 'a', '1 Peter 2:25 — "For ye were as sheep going astray; but are now returned unto the Shepherd and Bishop of your souls."');

-- ═══ 1 Peter Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Peter', 3, 'kids', 1, 'What kind of beauty does Peter say is most important?', 'The beauty inside your heart — a meek and quiet spirit', 'Wearing fancy clothes', 'Having pretty hair', 'Wearing gold jewelry', 'a', '1 Peter 3:3-4 — "Whose adorning let it not be that outward adorning... But let it be the hidden man of the heart... even the ornament of a meek and quiet spirit."'),
('1 Peter', 3, 'kids', 2, 'What should we always be ready to do?', 'Give an answer about our hope in God', 'Run a race really fast', 'Win an argument with everyone', 'Show off our Bible knowledge', 'a', '1 Peter 3:15 — "Be ready always to give an answer to every man that asketh you a reason of the hope that is in you."'),
('1 Peter', 3, 'kids', 3, 'What did Jesus do to bring us to God?', 'He suffered once for sins, the just for the unjust', 'He built a bridge from earth to heaven', 'He opened a magical door', 'He wrote a letter to God for us', 'a', '1 Peter 3:18 — "For Christ also hath once suffered for sins, the just for the unjust, that he might bring us to God."'),
-- Teens
('1 Peter', 3, 'teens', 1, 'What does Peter say about outward adornment for women?', 'Not the outward adorning of plaiting hair and wearing gold, but the hidden man of the heart', 'Always wear the finest clothes to honour God', 'Dress as plainly as possible to show humility', 'Only wear what the elders approve', 'a', '1 Peter 3:3-4 — "Whose adorning let it not be that outward adorning of plaiting the hair, and of wearing of gold, or of putting on of apparel; But let it be the hidden man of the heart."'),
('1 Peter', 3, 'teens', 2, 'What does Peter call a meek and quiet spirit?', 'Of great price in the sight of God', 'Weak and useless in this world', 'Acceptable but not necessary', 'Good only for women', 'a', '1 Peter 3:4 — "Even the ornament of a meek and quiet spirit, which is in the sight of God of great price."'),
('1 Peter', 3, 'teens', 3, 'What does Peter say husbands should give to their wives?', 'Honour, as unto the weaker vessel and as being heirs together of the grace of life', 'Commands, as the head of the household', 'Permission to speak in the assembly', 'Money for their personal needs', 'a', '1 Peter 3:7 — "Likewise, ye husbands, dwell with them according to knowledge, giving honour unto the wife, as unto the weaker vessel, and as being heirs together of the grace of life."'),
('1 Peter', 3, 'teens', 4, 'What should believers not render (give back) for evil?', 'Not evil for evil, or railing for railing, but contrariwise blessing', 'An equal measure of punishment', 'Silence and complete avoidance', 'A stern warning and rebuke', 'a', '1 Peter 3:9 — "Not rendering evil for evil, or railing for railing: but contrariwise blessing; knowing that ye are thereunto called, that ye should inherit a blessing."'),
('1 Peter', 3, 'teens', 5, 'What does Peter say about having a good conscience?', 'Having a good conscience so that those who speak evil of you as evildoers may be ashamed', 'A good conscience is unnecessary for believers', 'A good conscience comes naturally without effort', 'A good conscience only matters before God, not men', 'a', '1 Peter 3:16 — "Having a good conscience; that, whereas they speak evil of you, as of evildoers, they may be ashamed that falsely accuse your good conversation in Christ."'),
-- Adults
('1 Peter', 3, 'adults', 1, 'What Old Testament woman does Peter mention as an example for wives?', 'Sara, who obeyed Abraham, calling him lord', 'Ruth, who followed Naomi to Bethlehem', 'Esther, who saved her people from Haman', 'Deborah, who judged Israel', 'a', '1 Peter 3:6 — "Even as Sara obeyed Abraham, calling him lord: whose daughters ye are, as long as ye do well, and are not afraid with any amazement."'),
('1 Peter', 3, 'adults', 2, 'What does Peter say can be hindered if husbands do not honour their wives?', 'Their prayers', 'Their income', 'Their health', 'Their ministry', 'a', '1 Peter 3:7 — "That your prayers be not hindered."'),
('1 Peter', 3, 'adults', 3, 'How does Peter describe Christ''s suffering for sins in verse 18?', 'The just for the unjust, that he might bring us to God, being put to death in the flesh but quickened by the Spirit', 'As a temporary setback in God''s eternal plan', 'As an example of passive resistance', 'As a political sacrifice for Israel''s freedom', 'a', '1 Peter 3:18 — "For Christ also hath once suffered for sins, the just for the unjust, that he might bring us to God, being put to death in the flesh, but quickened by the Spirit."'),
('1 Peter', 3, 'adults', 4, 'To whom did Christ preach by the Spirit?', 'The spirits in prison', 'The angels in heaven', 'The saints in paradise', 'The prophets in the temple', 'a', '1 Peter 3:19 — "By which also he went and preached unto the spirits in prison."'),
('1 Peter', 3, 'adults', 5, 'When were the spirits in prison disobedient?', 'In the days of Noah, while the ark was a preparing', 'In the days of Moses at Mount Sinai', 'In the days of Abraham in Ur', 'In the days of David in Jerusalem', 'a', '1 Peter 3:20 — "Which sometime were disobedient, when once the longsuffering of God waited in the days of Noah, while the ark was a preparing."'),
('1 Peter', 3, 'adults', 6, 'How does Peter describe the saving work of baptism?', 'Not the putting away of the filth of the flesh, but the answer of a good conscience toward God, by the resurrection of Jesus Christ', 'The physical washing that cleanses the body', 'A ritual that guarantees salvation apart from faith', 'A symbolic act with no spiritual significance', 'a', '1 Peter 3:21 — "The like figure whereunto even baptism doth also now save us (not the putting away of the filth of the flesh, but the answer of a good conscience toward God,) by the resurrection of Jesus Christ."'),
('1 Peter', 3, 'adults', 7, 'What Psalm does Peter quote about the Lord''s eyes and ears?', 'Psalm 34 — "The eyes of the Lord are over the righteous, and his ears are open unto their prayers"', 'Psalm 23 — The Lord is my shepherd', 'Psalm 51 — Create in me a clean heart', 'Psalm 119 — Thy word is a lamp unto my feet', 'a', '1 Peter 3:12 — "For the eyes of the Lord are over the righteous, and his ears are open unto their prayers: but the face of the Lord is against them that do evil." This quotes Psalm 34:15-16.'),
('1 Peter', 3, 'adults', 8, 'Where is Christ now according to verse 22?', 'At the right hand of God, angels and authorities and powers being made subject unto him', 'In the temple in Jerusalem', 'Walking among the churches', 'Waiting in paradise until the resurrection', 'a', '1 Peter 3:22 — "Who is gone into heaven, and is on the right hand of God; angels and authorities and powers being made subject unto him."');

-- ═══ 1 Peter Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Peter', 4, 'kids', 1, 'What should we use our gifts from God to do?', 'Help and serve one another', 'Show off to our friends', 'Keep them for ourselves', 'Trade them for money', 'a', '1 Peter 4:10 — "As every man hath received the gift, even so minister the same one to another, as good stewards of the manifold grace of God."'),
('1 Peter', 4, 'kids', 2, 'If you suffer for being a Christian, should you be ashamed?', 'No, you should glorify God', 'Yes, you should hide your faith', 'Yes, you should stop believing', 'No, you should fight back', 'a', '1 Peter 4:16 — "Yet if any man suffer as a Christian, let him not be ashamed; but let him glorify God on this behalf."'),
('1 Peter', 4, 'kids', 3, 'What does Peter say we should have above all things?', 'Fervent love (charity) among yourselves', 'Lots of money in the bank', 'The biggest house on the street', 'The most toys and games', 'a', '1 Peter 4:8 — "And above all things have fervent charity among yourselves: for charity shall cover the multitude of sins."'),
-- Teens
('1 Peter', 4, 'teens', 1, 'What does Peter say about the time past of our lives?', 'The time past may suffice us to have wrought the will of the Gentiles', 'The past doesn''t matter at all anymore', 'We should always dwell on our past mistakes', 'The past was better than the present', 'a', '1 Peter 4:3 — "For the time past of our life may suffice us to have wrought the will of the Gentiles, when we walked in lasciviousness, lusts, excess of wine, revellings, banquetings, and abominable idolatries."'),
('1 Peter', 4, 'teens', 2, 'Why do former companions think it strange about believers?', 'Because believers no longer run with them to the same excess of riot', 'Because believers have become wealthy', 'Because believers have moved away', 'Because believers speak a different language', 'a', '1 Peter 4:4 — "Wherein they think it strange that ye run not with them to the same excess of riot, speaking evil of you."'),
('1 Peter', 4, 'teens', 3, 'What does charity (love) cover?', 'The multitude of sins', 'Only small offences', 'Nothing at all', 'Only the sins of friends', 'a', '1 Peter 4:8 — "For charity shall cover the multitude of sins."'),
('1 Peter', 4, 'teens', 4, 'What should believers not think strange about?', 'The fiery trial which is to try you', 'Having money problems', 'Making new friends', 'Learning difficult subjects', 'a', '1 Peter 4:12 — "Beloved, think it not strange concerning the fiery trial which is to try you, as though some strange thing happened unto you."'),
('1 Peter', 4, 'teens', 5, 'What should believers do if they suffer as a Christian?', 'Not be ashamed, but glorify God on this behalf', 'Fight back against the persecutors', 'Deny their faith to avoid trouble', 'Complain loudly to the authorities', 'a', '1 Peter 4:16 — "Yet if any man suffer as a Christian, let him not be ashamed; but let him glorify God on this behalf."'),
-- Adults
('1 Peter', 4, 'adults', 1, 'What does Peter mean by "arm yourselves likewise with the same mind"?', 'Since Christ suffered in the flesh, believers should adopt the same readiness to suffer, for he that hath suffered in the flesh hath ceased from sin', 'Put on physical armor for battle', 'Prepare mentally for academic study', 'Equip yourselves with earthly weapons', 'a', '1 Peter 4:1 — "Forasmuch then as Christ hath suffered for us in the flesh, arm yourselves likewise with the same mind: for he that hath suffered in the flesh hath ceased from sin."'),
('1 Peter', 4, 'adults', 2, 'To whom shall the living and dead give account?', 'Him that is ready to judge the quick and the dead', 'The Roman emperor', 'The Jewish Sanhedrin', 'The apostles in Jerusalem', 'a', '1 Peter 4:5 — "Who shall give account to him that is ready to judge the quick and the dead."'),
('1 Peter', 4, 'adults', 3, 'Why was the gospel preached to them that are dead?', 'That they might be judged according to men in the flesh, but live according to God in the spirit', 'So the dead could convert in the afterlife', 'To give the dead a second chance at salvation', 'To prove God''s power over death', 'a', '1 Peter 4:6 — "For for this cause was the gospel preached also to them that are dead, that they might be judged according to men in the flesh, but live according to God in the spirit."'),
('1 Peter', 4, 'adults', 4, 'What does Peter say about the end of all things?', 'The end of all things is at hand; be ye therefore sober, and watch unto prayer', 'The end is far away, so relax', 'The end has already passed', 'The end cannot be known by anyone', 'a', '1 Peter 4:7 — "But the end of all things is at hand: be ye therefore sober, and watch unto prayer."'),
('1 Peter', 4, 'adults', 5, 'How should those who speak in ministry speak?', 'As the oracles of God', 'As the philosophers of Greece', 'As the scribes of Israel', 'As the senators of Rome', 'a', '1 Peter 4:11 — "If any man speak, let him speak as the oracles of God."'),
('1 Peter', 4, 'adults', 6, 'Where does Peter say judgment must begin?', 'At the house of God', 'At the throne of Caesar', 'At the gates of Jerusalem', 'At the temple of Diana', 'a', '1 Peter 4:17 — "For the time is come that judgment must begin at the house of God: and if it first begin at us, what shall the end be of them that obey not the gospel of God?"'),
('1 Peter', 4, 'adults', 7, 'If the righteous scarcely be saved, what question does Peter raise?', 'Where shall the ungodly and the sinner appear?', 'How shall the righteous be rewarded?', 'When shall the prophets return?', 'Why shall the wicked prosper?', 'a', '1 Peter 4:18 — "And if the righteous scarcely be saved, where shall the ungodly and the sinner appear?"'),
('1 Peter', 4, 'adults', 8, 'What should those who suffer according to the will of God do?', 'Commit the keeping of their souls to him in well doing, as unto a faithful Creator', 'Demand immediate vindication from God', 'Withdraw from all social contact', 'Seek revenge when the opportunity arises', 'a', '1 Peter 4:19 — "Wherefore let them that suffer according to the will of God commit the keeping of their souls to him in well doing, as unto a faithful Creator."');

-- ═══ 1 Peter Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Peter', 5, 'kids', 1, 'Who does Peter tell to feed (take care of) the flock of God?', 'The elders', 'The children', 'The Roman soldiers', 'The rich merchants', 'a', '1 Peter 5:1-2 — "The elders which are among you I exhort... Feed the flock of God which is among you."'),
('1 Peter', 5, 'kids', 2, 'What animal does Peter compare the devil to?', 'A roaring lion', 'A sneaky snake', 'A big bear', 'A hungry wolf', 'a', '1 Peter 5:8 — "Your adversary the devil, as a roaring lion, walketh about, seeking whom he may devour."'),
('1 Peter', 5, 'kids', 3, 'What should you do with your worries?', 'Give them to God because he cares for you', 'Keep them all to yourself', 'Tell everyone your problems', 'Pretend you have no worries', 'a', '1 Peter 5:7 — "Casting all your care upon him; for he careth for you."'),
-- Teens
('1 Peter', 5, 'teens', 1, 'How should elders shepherd the flock?', 'Not by constraint but willingly; not for filthy lucre but of a ready mind', 'By strict rules and heavy penalties', 'By hiring others to do the work', 'By only preaching on Sundays', 'a', '1 Peter 5:2 — "Feed the flock of God which is among you, taking the oversight thereof, not by constraint, but willingly; not for filthy lucre, but of a ready mind."'),
('1 Peter', 5, 'teens', 2, 'What does Peter say younger people should do?', 'Submit to the elder, and all be clothed with humility', 'Challenge the elders at every opportunity', 'Ignore the elders and follow their own plans', 'Take leadership from the elders by force', 'a', '1 Peter 5:5 — "Likewise, ye younger, submit yourselves unto the elder. Yea, all of you be subject one to another, and be clothed with humility."'),
('1 Peter', 5, 'teens', 3, 'What does God give to the humble?', 'Grace — God resisteth the proud and giveth grace to the humble', 'Wealth and power beyond measure', 'Freedom from all suffering', 'Angels to serve their every need', 'a', '1 Peter 5:5 — "God resisteth the proud, and giveth grace to the humble."'),
('1 Peter', 5, 'teens', 4, 'What does Peter say to do under God''s mighty hand?', 'Humble yourselves, that he may exalt you in due time', 'Stand tall and demand your rights', 'Complain until God blesses you', 'Do nothing and wait for a miracle', 'a', '1 Peter 5:6 — "Humble yourselves therefore under the mighty hand of God, that he may exalt you in due time."'),
('1 Peter', 5, 'teens', 5, 'Who does Peter say helped him write this letter?', 'Silvanus, a faithful brother', 'Timothy, a young pastor', 'Luke, a beloved physician', 'Barnabas, the son of consolation', 'a', '1 Peter 5:12 — "By Silvanus, a faithful brother unto you, as I suppose, I have written briefly."'),
-- Adults
('1 Peter', 5, 'adults', 1, 'What does Peter call himself among the elders?', 'A fellow elder and witness of the sufferings of Christ, and a partaker of the glory that shall be revealed', 'The chief apostle over all elders', 'The bishop of Rome appointed by Christ', 'The greatest of all the apostles', 'a', '1 Peter 5:1 — "The elders which are among you I exhort, who am also an elder, and a witness of the sufferings of Christ, and also a partaker of the glory that shall be revealed."'),
('1 Peter', 5, 'adults', 2, 'What should elders not be?', 'Lords over God''s heritage, but ensamples to the flock', 'Friends with the congregation', 'Gentle and patient with sinners', 'Willing to serve without pay', 'a', '1 Peter 5:3 — "Neither as being lords over God''s heritage, but being ensamples to the flock."'),
('1 Peter', 5, 'adults', 3, 'What will the chief Shepherd give when he shall appear?', 'A crown of glory that fadeth not away', 'A crown of thorns to share in his suffering', 'A golden scepter of earthly authority', 'A mansion in the heavenly city', 'a', '1 Peter 5:4 — "And when the chief Shepherd shall appear, ye shall receive a crown of glory that fadeth not away."'),
('1 Peter', 5, 'adults', 4, 'After believers have suffered a while, what does the God of all grace do?', 'Make you perfect, stablish, strengthen, settle you', 'Remove all suffering permanently', 'Grant immediate revenge on enemies', 'Transport them directly to heaven', 'a', '1 Peter 5:10 — "But the God of all grace, who hath called us unto his eternal glory by Christ Jesus, after that ye have suffered a while, make you perfect, stablish, strengthen, settle you."'),
('1 Peter', 5, 'adults', 5, 'What does Peter call "Babylon" in his closing greetings?', 'The church that is at Babylon, elected together with you — widely understood as a reference to Rome', 'A literal city in Mesopotamia', 'A small village near Jerusalem', 'An imaginary place representing heaven', 'a', '1 Peter 5:13 — "The church that is at Babylon, elected together with you, saluteth you." Most scholars understand "Babylon" as a cryptic reference to Rome.'),
('1 Peter', 5, 'adults', 6, 'Who does Peter mention as greeting the readers along with the church?', 'Marcus my son — referring to John Mark', 'Timothy my true son in the faith', 'Luke the beloved physician', 'Apollos the eloquent preacher', 'a', '1 Peter 5:13 — "And so doth Marcus my son."'),
('1 Peter', 5, 'adults', 7, 'How does Peter describe Silvanus in verse 12?', 'A faithful brother', 'A mighty prophet', 'A skilled physician', 'A wealthy supporter', 'a', '1 Peter 5:12 — "By Silvanus, a faithful brother unto you, as I suppose, I have written briefly."'),
('1 Peter', 5, 'adults', 8, 'What does Peter say is the true grace of God in verse 12?', 'This is the true grace of God wherein ye stand', 'The ability to speak in tongues', 'The power to perform miracles', 'The gift of prophetic visions', 'a', '1 Peter 5:12 — "Exhorting, and testifying that this is the true grace of God wherein ye stand."');
